+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -9783,20 +9783,24 @@ preparePlanForEpilogueVectorLoop(VPlan &Plan, Loop *L,
       // FIXME: Improve modeling for canonical IV start values in the epilogue
       // loop.
       using namespace llvm::PatternMatch;
-      Type *IdxTy = IV->getScalarType();
-      PHINode *EPResumeVal = find_singleton<PHINode>(
-          L->getLoopPreheader()->phis(),
-          [&EPI, IdxTy](PHINode &P, bool) -> PHINode * {
-            if (P.getType() == IdxTy &&
-                match(
-                    P.getIncomingValueForBlock(EPI.MainLoopIterationCountCheck),
-                    m_SpecificInt(0)) &&
-                all_of(P.incoming_values(), [&EPI](Value *Inc) {
-                  return Inc == EPI.VectorTripCount ||
-                         match(Inc, m_SpecificInt(0));
-                }))
-              return &P;
-            return nullptr;
-          });
+      PHINode *EPResumeVal = nullptr;
+      for (PHINode &P : L->getLoopPreheader()->phis()) {
+        if (P.getType() == IV->getScalarType() &&
+            P.getNumIncomingValues() == 2) {
+          // Check if this is the canonical IV resume phi.
+          // It should have two incoming values:
+          // 1. From EPI.MainLoopIterationCountCheck with value 0
+          // 2. From the vector loop exit with value EPI.VectorTripCount
+          Value *FromCheck = P.getIncomingValueForBlock(EPI.MainLoopIterationCountCheck);
+          if (!match(FromCheck, m_SpecificInt(0)))
+            continue;
+          // Find the other incoming value (not from EPI.MainLoopIterationCountCheck)
+          for (unsigned i = 0; i < 2; i++) {
+            if (P.getIncomingBlock(i) != EPI.MainLoopIterationCountCheck &&
+                P.getIncomingValue(i) == EPI.VectorTripCount) {
+              EPResumeVal = &P;
+              break;
+            }
+          }
+        }
+      }
       assert(EPResumeVal && "must have a resume value for the canonical IV");
